fn pm_msgs_contiguous_from_base() {
    // PM requests are contiguous from PM_RQ_BASE; NR_PM_MSGS locks the PM
    // server's dispatch coverage.
    let msgs = [PM_GETPID];
    for (i, m) in msgs.iter().enumerate() {
        assert_eq!(*m, PM_RQ_BASE + i as i32);
    }
