    if n % KCALL_TRACE_EVERY == 0 {
        let call_idx = original_m_type - KERNEL_CALL;
        let mut uart = Uart::new();
        let _ = writeln!(
            uart,
            "[ksys {n}] caller={caller_nr} call={call_idx} result={result}",
        );
    }

