3	//! `NOTIFY` — non-blocking notification.
4	//!
5	//! Translation of MINIX 3 `kernel/proc.c:1132 mini_notify()`. Never
6	//! blocks the caller. If the destination is `RECEIVE`-blocked and would
7	//! accept a message from the caller (or `ANY`), the kernel synthesizes a
8	//! [`NOTIFY_MESSAGE`]-typed message directly into the destination's
9	//! `deliver_msg` and unblocks them. Otherwise it sets a bit in the
10	//! destination's `priv.notify_pending` bitmap so the next `RECEIVE` will
11	//! collect the deferred notification.
12	
13	use core::sync::atomic::Ordering;
14	
15	use minixrs_kernel_shared::com::{CLOCK, NR_SYS_PROCS};
16	use minixrs_kernel_shared::endpoint::{ANY, Endpoint, endpoint_proc};
17	use minixrs_kernel_shared::error::{EBADSRCDST, ECALLDENIED, OK};
18	use minixrs_kernel_shared::ipc_const::NOTIFY_MESSAGE;
19	use minixrs_kernel_shared::message::Message;
20	
21	use crate::proc::bitmap::{get_sys_bit, set_sys_bit};
22	use crate::proc::flags::{MF_DELIVERMSG, MF_REPLY_PEND, RTS_RECEIVING, RTS_SENDING};
23	use crate::proc::table::{N_PROC_SLOTS, proc_index};
24	use crate::proc::{Priv, Proc, sched};
25	
26	/// MINIX 3 `WILLRECEIVE(dst, src_e)`. Returns true when `dst` is blocked
27	/// in `RECEIVE` (and not also in `SEND`, to dodge the SENDREC mid-flight
28	/// case) and its receive-from filter matches `src_e`.
29	pub(crate) fn will_receive(dst: &Proc, src_e: Endpoint) -> bool {
30	    let rts = dst.rts_flags.load(Ordering::Relaxed);
31	    if rts & RTS_RECEIVING == 0 || rts & RTS_SENDING != 0 {
32	        return false;
33	    }
34	    let getfrom = dst.getfrom_e;
