49	/// `NOTIFY` primitive. Returns `OK` on success or an IPC error code.
50	pub fn mini_notify(
51	    proc_table: &mut [Proc; N_PROC_SLOTS],
52	    priv_table: &mut [Priv; NR_SYS_PROCS],
53	    caller_nr: minixrs_kernel_shared::ProcNr,
