1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! `SYS_SCHEDULE` / `SYS_SCHEDCTL` — the kernel mechanism behind the
4	//! delegatable scheduler (slice 4.3).
5	//!
6	//! minix.rs keeps the priority-banded run queue in the kernel but makes it
7	//! *delegatable*: a user-space scheduler (SCHED) drives policy through these two
8	//! calls, exactly as VM drives paging policy through `SYS_VMCTL`. Both name a
9	//! *target* process by endpoint, so — like `do_vmctl` — they take the whole
10	//! `&mut [Proc]` slice + `caller_nr` and are routed specially in
11	//! [`kernel_call_dispatch`](super::kernel_call_dispatch).
12	//!
13	//! - [`do_schedule`] sets a target's priority + quantum and (re-)admits it to the
14	//!   run queue. SCHED issues it in response to `SCHEDULING_NO_QUANTUM` (re-admit
15	//!   a preempted proc) and at `SCHEDULING_START` (initial assignment).
16	//! - [`do_schedctl`] claims a target (`target.scheduler = caller`) or releases it
17	//!   back to the kernel scheduler (`SCHEDCTL_FLAG_KERNEL` → `scheduler = NONE`).
18	//!
19	//! ## Trust model
20	//!
21	//! Identical to `do_vmctl`: the single gate is `Priv::k_call_mask` granting the
22	//! call, checked in `kernel_call_dispatch` before we run. A caller that reaches
23	//! here may name any process. SCHED is the intended sole holder; if a
24	//! less-trusted process is later granted these calls, per-target authorization
25	//! must be added first.
26	//!
27	//! ## Message payload layout (offsets within `Message::payload`)
28	//!
29	//! | offset | field            | direction | call          |
30	//! |--------|------------------|-----------|---------------|
31	//! |  0..4  | target endpoint  | in        | `SYS_SCHEDULE`|
32	//! |  4..8  | priority (i32)   | in        | `SYS_SCHEDULE`|
33	//! |  8..12 | quantum_ms (i32) | in        | `SYS_SCHEDULE`|
34	//! |  0..4  | flags (i32)      | in        | `SYS_SCHEDCTL`|
35	//! |  4..8  | target endpoint  | in        | `SYS_SCHEDCTL`|
36	
37	use core::fmt::Write;
38	use core::sync::atomic::{AtomicU64, Ordering};
39	
40	use minixrs_kernel_shared::ProcNr;
41	use minixrs_kernel_shared::callnr::SCHEDCTL_FLAG_KERNEL;
42	use minixrs_kernel_shared::endpoint::{Endpoint, NONE, SELF, endpoint_proc};
43	use minixrs_kernel_shared::error::{EINVAL, OK};
44	use minixrs_kernel_shared::message::Message;
45	
46	use crate::proc::Proc;
47	use crate::proc::flags::RTS_NO_QUANTUM;
48	use crate::proc::sched::{self, NR_SCHED_QUEUES};
49	use crate::proc::table::{N_PROC_SLOTS, proc_index};
50	use crate::uart::Uart;
51	
52	/// Leading `SYS_SCHEDULE` calls to trace explicitly — the scheduler-side half of
53	/// the delegation round-trip (`[noq]` in `sched::reschedule` is the kernel-side
54	/// half). A head carve-out is needed because SCHED's re-admits are ~0.1% of the
55	/// kernel-call flood, so the modulo-100 `[ksys]` sampler rarely catches them
56	/// (same reasoning as `do_vmctl::VMCTL_TRACE_HEAD`).
57	const SCHED_TRACE_HEAD: u64 = 6;
58	static SCHED_COUNT: AtomicU64 = AtomicU64::new(0);
59	
60	/// `SYS_SCHEDULE` — set a target's priority + quantum and (re-)admit it.
61	///
62	/// Reads the target endpoint (`SELF` allowed), priority, and quantum from the
63	/// payload; validates them; updates the proc slot; then re-admits the proc:
64	///
65	/// - If the target is **off** the run queue (the `SCHEDULING_NO_QUANTUM` case —
66	///   `reschedule` dequeued it and left `RTS_NO_QUANTUM` set),
67	///   [`sched::rts_unset`] clears the no-quantum block and enqueues it in the
68	///   (possibly new) priority band.
69	/// - If the target is **on** the run queue (runnable already), its band may have
70	///   changed, so move it with `dequeue` + `enqueue`.
71	pub(super) fn do_schedule(
72	    proc_table: &mut [Proc; N_PROC_SLOTS],
73	    caller_nr: ProcNr,
74	    msg: &mut Message,
75	) -> i32 {
76	    let target_e: Endpoint = read_i32(msg, 0);
77	    let priority = read_i32(msg, 4);
78	    let quantum_ms = read_i32(msg, 8);
79	
80	    let target_nr = if target_e == SELF {
81	        caller_nr
82	    } else {
83	        endpoint_proc(target_e)
84	    };
85	    let Some(target_idx) = proc_index(target_nr) else {
86	        return EINVAL;
87	    };
88	
89	    // Priority must name a real band; quantum must be positive. An out-of-range
90	    // priority would otherwise trip `enqueue`'s `prio < NR_SCHED_QUEUES` assert.
91	    if !(0..NR_SCHED_QUEUES as i32).contains(&priority) || quantum_ms <= 0 {
92	        return EINVAL;
93	    }
94	
95	    let (nr, was_runnable, name0) = {
96	        let p = &mut proc_table[target_idx];
97	        let was_runnable = p.rts_flags.load(Ordering::Relaxed) == 0;
98	        p.priority = priority as u8;
99	        p.quantum_ms = quantum_ms as u32;
100	        p.quantum_left = quantum_ms as u64;
101	        (p.nr, was_runnable, p.name[0])
102	    };
103	
104	    // SAFETY: the `p` borrow above has ended (NLL); rts_unset / dequeue / enqueue
105	    // re-borrow `target_idx`'s slot internally. Single-threaded EL1 context, same
106	    // invariant as `do_vmctl`.
107	    unsafe {
108	        if was_runnable {
109	            // Already on the run queue; the new priority may belong to a
110	            // different band, so move it.
111	            sched::dequeue(nr);
112	            sched::enqueue(nr);
113	        } else {
114	            // Off the run queue (preempted, RTS_NO_QUANTUM set): clear the
115	            // no-quantum block and re-admit. rts_unset enqueues in the new band
116	            // if this makes the proc runnable.
117	            sched::rts_unset(&mut proc_table[target_idx], RTS_NO_QUANTUM);
118	        }
119	    }
120	
121	    let n = SCHED_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
122	    if n <= SCHED_TRACE_HEAD {
123	        let _ = writeln!(
124	            Uart::new(),
125	            "[ksys SYS_SCHEDULE] target={} nr={} prio={priority} quantum={quantum_ms} result=0",
126	            name0 as char,
127	            nr.get(),
128	        );
129	    }
130	    OK
131	}
132	
133	/// `SYS_SCHEDCTL` — claim a target for the caller's scheduler, or release it
134	/// back to the kernel scheduler.
135	///
136	/// `SCHEDCTL_FLAG_KERNEL` set → `target.scheduler = NONE` (kernel-scheduled);
137	/// otherwise the caller claims the target (`target.scheduler = caller`). The
138	/// change takes effect at the target's next quantum exhaustion (see
139	/// `sched::reschedule`); no immediate run-queue transition is needed.
140	pub(super) fn do_schedctl(
141	    proc_table: &mut [Proc; N_PROC_SLOTS],
142	    caller_nr: ProcNr,
143	    msg: &mut Message,
144	) -> i32 {
145	    let flags = read_i32(msg, 0);
146	    let target_e: Endpoint = read_i32(msg, 4);
147	
148	    let target_nr = if target_e == SELF {
149	        caller_nr
150	    } else {
151	        endpoint_proc(target_e)
152	    };
153	    let Some(target_idx) = proc_index(target_nr) else {
154	        return EINVAL;
155	    };
156	
157	    // Snapshot the caller's endpoint before borrowing the target mutably (the
158	    // two may be the same slot when a process claims itself).
159	    let caller_endpoint = {
160	        let caller_idx = proc_index(caller_nr).expect("caller in proc table");
161	        proc_table[caller_idx].endpoint
162	    };
163	
164	    let p = &mut proc_table[target_idx];
165	    p.scheduler = if flags & SCHEDCTL_FLAG_KERNEL != 0 {
166	        NONE
167	    } else {
168	        caller_endpoint
169	    };
170	    OK
171	}
172	
173	#[inline]
174	fn read_i32(msg: &Message, off: usize) -> i32 {
175	    i32::from_ne_bytes(
176	        msg.payload[off..off + 4]
177	            .try_into()
178	            .expect("payload in range"),
179	    )
180	}
