fn unlink_from_caller_q(
    proc_table: &mut [Proc; N_PROC_SLOTS],
    target_idx: usize,
    sendto_e: Endpoint,
) {
    let Some(dst_idx) = proc_index(endpoint_proc(sendto_e)) else {
        return;
