    for slot in 0..NR_BOOT_PROCS {
        if slot == pm || slot == init {
            continue;
        }
        t[slot] = MProc {
            pid: next_pid,
            parent_slot: if slot == rs { pm } else { rs },
            flags: MF_IN_USE | MF_PRIV_PROC,
        };
        next_pid += 1;
    }

    // Demo stubs: ordinary user processes, parented to INIT, pids continuing
    // past the servers (slots 11..=15 land on pids 11..=15).
    for slot in NR_BOOT_PROCS..NR_BOOT_PROCS + NR_STUB_PROCS {
        t[slot] = MProc {
            pid: next_pid,
            parent_slot: init,
            flags: MF_IN_USE,
        };
        next_pid += 1;
    }
}

toolUseResult.newString:
    let mut next_pid = 2;
    for (slot, e) in t.iter_mut().enumerate().take(NR_BOOT_PROCS) {
        if slot == pm || slot == init {
            continue;
        }
        *e = MProc {
            pid: next_pid,
            parent_slot: if slot == rs { pm } else { rs },
            flags: MF_IN_USE | MF_PRIV_PROC,
        };
        next_pid += 1;
    }

    // Demo stubs: ordinary user processes, parented to INIT, pids continuing
    // past the servers (slots 11..=15 land on pids 11..=15).
    for e in t.iter_mut().skip(NR_BOOT_PROCS).take(NR_STUB_PROCS) {
        *e = MProc {
            pid: next_pid,
            parent_slot: init,
            flags: MF_IN_USE,
        };
        next_pid += 1;
    }
}

input.old_string:
for slot in 0..NR_BOOT_PROCS {
    assert_eq!(t[slot].flags, MF_IN_USE | MF_PRIV_PROC, "slot {slot}");
}

input.new_string:
for (slot, e) in t.iter().enumerate().take(NR_BOOT_PROCS) {
    assert_eq!(e.flags, MF_IN_USE | MF_PRIV_PROC, "slot {slot}");
}

toolUseResult.oldString:
for slot in 0..NR_BOOT_PROCS {
    assert_eq!(t[slot].flags, MF_IN_USE | MF_PRIV_PROC, "slot {slot}");
}

toolUseResult.newString:
for (slot, e) in t.iter().enumerate().take(NR_BOOT_PROCS) {
